import io.restassured.RestAssured;
import io.restassured.response.Response;
import static io.restassured.RestAssured.*;
import static org.hamcrest.Matchers.*;

public class ApiTest {

    @BeforeClass
    public static void setup() {
        RestAssured.baseURI = "https://reqres.in";
        RestAssured.basePath = "/api";
    }

    // ── GET REQUEST ───────────────────────────────────────────────────
    @Test
    public void testGetUser() {
        given()
            .header("Accept", "application/json")
        .when()
            .get("/users/2")
        .then()
            .statusCode(200)
            .body("data.id", equalTo(2))
            .body("data.first_name", equalTo("Janet"))
            .body("data.email", containsString("@reqres.in"))
            .time(lessThan(2000L)); // Response time < 2 seconds
    }

    // ── POST REQUEST ──────────────────────────────────────────────────
    @Test
    public void testCreateUser() {
        String requestBody = """
            {
                "name": "John Doe",
                "job": "SDET"
            }
            """;

        given()
            .contentType("application/json")
            .body(requestBody)
        .when()
            .post("/users")
        .then()
            .statusCode(201)
            .body("name", equalTo("John Doe"))
            .body("job", equalTo("SDET"))
            .body("id", notNullValue())
            .body("createdAt", notNullValue());
    }

    // ── EXTRACT RESPONSE ──────────────────────────────────────────────
    @Test
    public void testExtractUserId() {
        String userId = 
            given()
                .contentType("application/json")
                .body("{ \"name\": \"Alice\", \"job\": \"Tester\" }")
            .when()
                .post("/users")
            .then()
                .statusCode(201)
                .extract()
                .path("id");  // Extract specific field

        System.out.println("Created user ID: " + userId);
        Assert.assertNotNull(userId);
    }

    // ── EXTRACT FULL RESPONSE ─────────────────────────────────────────
    @Test  
    public void testExtractFullResponse() {
        Response response = 
            given()
                .queryParam("page", 2)
            .when()
                .get("/users")
            .then()
                .statusCode(200)
                .extract()
                .response();

        int total = response.jsonPath().getInt("total");
        List<String> emails = response.jsonPath().getList("data.email");
        System.out.println("Total users: " + total);
        System.out.println("Emails: " + emails);
    }
}
